I18N.register("es", {
  tips: {
    "Look at Rows and Columns Separately": ["Mirar filas y columnas por separado", "En una cuadrícula de números, primero verifique cada fila y luego cada columna. A menudo una dirección sigue una regla simple: contar de 2 a 2 o de 3 a 3."],
    "Find the Rule Between Numbers": ["Encuentra la regla entre los números.", "Pregúntese: ¿Qué debo sumar, restar, multiplicar o dividir para pasar de un número al siguiente? Pruebe cada operación hasta que encuentre una que funcione para cada paso."],
    "Watch for Repeating Groups": ["Cuidado con los grupos repetidos", "A veces un grupo de formas o símbolos se repite sin cesar. Cuente cuántos elementos tiene el grupo y luego vea en qué parte del ciclo se encuentra."],
    "Use Elimination": ["Eliminación de uso", "Si no estás seguro, prueba cada respuesta: colócala en el patrón y comprueba si la regla aún funciona. Elimina cualquier respuesta que rompa el patrón."],
    "Find the Difference": ["busca la diferencia", "Resta cada número del anterior. Si la diferencia es siempre la misma, la regla es simple suma o resta."],
    "Try Multiplying or Dividing": ["Intenta multiplicar o dividir", "Divide cada número por el número anterior. Si obtiene el mismo resultado cada vez, la cadena se multiplica o divide por el mismo factor."],
    "Check for Two-Step Rules": ["Consulta las reglas en dos pasos", "A veces la regla combina dos operaciones (por ejemplo, primero +2, luego ×2). Escribe los pasos en el borrador y síguelos en orden."],
    "Write It Down": ["Escríbelo en papel", "Escribe los números y las diferencias o razones debajo de ellos. En el papel puedes ver el patrón más fácilmente que a simple vista."],
    "Read Every Word Carefully": ["Lee cada palabra atentamente", "En lógica, los detalles importan: palabras pequeñas como «todos», «algunos», «ninguno», «ciertamente» cambian el significado. Lea la pregunta dos veces antes de elegir."],
    "Draw a Picture or List": ["Dibuja o haz una lista", "Describe las personas, los días o las relaciones en el problema. Una simple lista o dibujo muestra claramente quién es más grande, quién viene primero, etc."],
    "Watch Out for Traps": ["Cuidado con las trampas", "De \"todos los perros son animales\" no se sigue \"todos los animales son perros\". No inviertas la regla por error."],
    "Use 'If... Then...' Thinking": ["Piensa \"si... entonces...\"", "Reformule las afirmaciones como «si A, entonces B». Sigue la cadena: si A es verdadera, ¿qué debe ser verdadero a continuación?"],
    "Picture It in Your Mind": ["Imagínalo en tu mente", "Para formas y cubos, intente \"ver\" la rotación o el plegado. Puedes dibujar un boceto rápido en el borrador."],
    "Know the Basics of Common Shapes": ["Conoce los conceptos básicos de las formas comunes.", "El cubo tiene 6 caras, 12 aristas, 8 vértices. El prisma triangular tiene 5 caras. Repita estos hechos y se volverán automáticos."],
    "Count What You Cannot See": ["Cuenta y lo que no se ve.", "En los cubos pegados, las caras ocultas donde se tocan no cuentan como caras visibles. Resta las caras \"pegados\" del total."],
    "Use Nets to Understand Folding": ["Utilice el despliegue para comprender el plegado", "El despliegue (el \"cuadrado\" cortado que se pliega formando un cubo) muestra qué caras son vecinas. Sigue una cara y mira con cuál se queda."],
    "Read the Problem Twice": ["Lee el problema dos veces", "Muchos problemas de trampas se basan en la prisa. La segunda lectura capta frases como \"todos menos...\" o \"permanecen\"."],
    "Look for Trick Words": ["Buscar palabras clave trampa", "Expresiones como \"todos menos\", \"permanecen\", \"en total\", \"cada uno\" cambian el cálculo. Subráyalos."],
    "Break It Into Steps": ["Dividir en pasos", "Resuelve por turnos: primero lo que sabes con certeza, luego suma o resta según el problema. No intentes todo a la vez."],
    "Check Your Answer": ["Comprueba la respuesta", "Después de calcular, vuelve a la pregunta: ¿Tiene sentido la respuesta en la historia? Rehaga el cálculo una vez más si es necesario."],
  },
  q: {
    "TPR811_1_01": ["¿Qué sigue en la fila? 2, 4, 6, 8, __", "Cuente de 2 a 2.", ["9", "10", "12", "11"], "La cuerda aumenta en 2 en cada paso: 2, 4, 6, 8, 10."],
    "TPR811_1_02": ["¿Qué sigue? 5, 10, 15, 20, __", "Los números son múltiplos del mismo número base.", ["22", "30", "25", "24"], "La cuerda aumenta en 5 en cada paso: 5, 10, 15, 20, 25."],
    "TPR811_1_03": ["¿Qué sigue? 3, 6, 9, 12, __", "Piense en multiplicar por 3 (el tablero de 3).", ["14", "15", "16", "13"], "La cuerda aumenta en 3 en cada paso: 3, 6, 9, 12, 15."],
    "TPR811_1_04": ["¿Qué sigue? 10, 20, 30, 40, __", "Cuente de 10 a 10.", ["45", "55", "50", "60"], "La cuerda aumenta en 10 en cada paso: 10, 20, 30, 40, 50."],
    "TPR811_1_05": ["¿Qué sigue? 4, 8, 12, 16, __", "Son múltiplos de 4.", ["18", "22", "24", "20"], "La cuerda aumenta en 4 en cada paso: 4, 8, 12, 16, 20."],
    "TPR811_1_06": ["¿Cuál es el número que falta? 1, 3, 5, __, 9", "Son números impares.", ["6", "8", "7", "4"], "Son números impares que aumentan de 2: 1, 3, 5, 7, 9."],
    "TPR811_1_07": ["¿Qué sigue? 2, 5, 8, 11, __", "¿Cuánto suma cada vez?", ["12", "13", "15", "14"], "Cada número es 3 más que el anterior: 2, 5, 8, 11, 14."],
    "TPR811_1_08": ["¿Cuál es el número que falta? 6, 12, __, 24, 30", "Cuente de 6 a 6.", ["15", "18", "20", "16"], "La cuerda aumenta de 6: 6, 12, 18, 24, 30."],
    "TPR811_1_09": ["¿Qué sigue en la fila? ○, □, ○, □, ○, __", "Las formas se alternan.", ["○", "△", "□", "◇"], "Se alternan círculo y cuadrado. Después del círculo viene el cuadrado: ○, □, ○, □, ○, □."],
    "TPR811_1_10": ["¿Qué sigue? 7, 14, 21, 28, __", "Piensa en multiplicar por 7 (el tablero del 7).", ["30", "32", "36", "35"], "La cuerda aumenta en 7 en cada paso: 7, 14, 21, 28, 35."],
    "TPR811_1_11": ["¿Cuál es el número que falta? 10, __, 30, 40, 50", "Cuente de 10 a 10.", ["15", "25", "20", "12"], "La cadena aumenta de 10: 10, 20, 30, 40, 50."],
    "TPR811_1_12": ["¿Qué sigue? 1, 4, 7, 10, __", "¿Cuánto suma cada vez?", ["12", "14", "11", "13"], "Cada número es 3 más que el anterior: 1, 4, 7, 10, 13."],
    "TPR811_1_13": ["¿Qué sigue en la fila? A, B, A, B, A, __", "Las letras se alternan.", ["un", "c", "b", "re"], "Alternar A y B: A, B, A, B, A, B."],
    "TPR811_1_14": ["¿Qué sigue? 8, 16, 24, 32, __", "Son múltiplos de 8.", ["36", "38", "40", "42"], "La cuerda aumenta de 8: 8, 16, 24, 32, 40."],
    "TPR811_1_15": ["¿Cuál es el número que falta? 5, 10, __, 20, 25", "Cuente de 5 a 5.", ["12", "14", "16", "15"], "La cuerda aumenta de 5: 5, 10, 15, 20, 25."],
    "TPR811_1_16": ["¿Qué sigue? 9, 18, 27, 36, __", "Son múltiplos de 9.", ["45", "40", "42", "44"], "La cuerda aumenta de 9: 9, 18, 27, 36, 45."],
    "TPR811_1_17": ["¿Qué sigue en la fila? ★, ♥, ★, ♥, ★, __", "Se alternan dos símbolos.", ["★", "♥", "♦", "○"], "Estrella y corazón se alternan: ★, ♥, ★, ♥, ★, ♥."],
    "TPR811_1_18": ["¿Cuál es el número que falta? 2, 4, __, 8, 10", "Cuente de 2 a 2.", ["5", "7", "6", "3"], "La cuerda aumenta de 2: 2, 4, 6, 8, 10."],
    "TPR811_1_19": ["¿Qué sigue? 11, 22, 33, 44, __", "Son múltiplos de 11.", ["50", "55", "54", "56"], "La cuerda aumenta desde 11: 11, 22, 33, 44, 55."],
    "TPR811_1_20": ["¿Qué sigue en la fila? 1, 2, 1, 2, 1, __", "Los números siempre repiten lo mismo.", ["1", "3", "2", "0"], "Los números 1 y 2 se alternan: 1, 2, 1, 2, 1, 2."],
    "TPR811_2_01": ["En una cuadrícula, la fila 1 es: 2, 4, 6, 8. la fila 2 es: 3, 6, 9, 12. la fila 3 es: 4, 8, __, 16. ¿Cuál es el número que falta?", "Cada fila contiene múltiplos del primer número de esa fila.", ["10", "11", "12", "14"], "La fila 3 contiene múltiplos de 4: 4, 8, 12, 16."],
    "TPR811_2_02": ["¿Qué sigue? 1, 2, 4, 8, __", "Cada número se duplica.", ["10", "12", "14", "16"], "Cada número se multiplica por 2: 1, 2, 4, 8, 16."],
    "TPR811_2_03": ["¿Qué sigue? 3, 9, 27, __", "Cada número se multiplica por el mismo factor.", ["36", "54", "81", "30"], "Cada número se multiplica por 3: 3, 9, 27, 81."],
    "TPR811_2_04": ["¿Qué sigue en el encordado? △, △, □, △, △, □, △, △, __", "Encuentra el grupo de símbolos repetidos.", ["△", "□", "○", "★"], "El patrón se repite △, △, □ siempre igual. La posición 9 es □."],
    "TPR811_2_05": ["Cuadrícula: La fila 1 es 1, 2, 3. La fila 2 es 2, 4, 6. La fila 3 es 3, 6, __. ¿Cuál es el número que falta?", "Cada fila multiplica la primera fila por el número de fila.", ["7", "8", "9", "10"], "Fila 3 = fila superior × 3. Entonces 3 × 3 = 9."],
    "TPR811_2_06": ["¿Qué sigue? 2, 6, 18, 54, __", "Multiplica por el mismo número cada vez.", ["108", "162", "72", "60"], "Cada número se multiplica por 3: 2, 6, 18, 54, 162."],
    "TPR811_2_07": ["¿Qué sigue? 64, 32, 16, __", "Cada número se divide por la mitad.", ["12", "10", "4", "8"], "Cada número es divisible por 2: 64, 32, 16, 8."],
    "TPR811_2_08": ["Cuadrícula: La fila 1 es 1, 3, 5, 7. La fila 2 es 2, 6, 10, 14. La fila 3 es 3, 9, __, 21. ¿Cuál es el número que falta?", "Fila 2 = Fila 1 × 2. ¿Cuánto cuesta la Fila 3?", ["12", "15", "13", "17"], "Fila 3 = Fila 1 × 3. Entonces 5 × 3 = 15."],
    "TPR811_2_09": ["¿Qué sigue? 4, 8, 16, 32, __", "Cada número se duplica.", ["48", "40", "64", "36"], "Cada número se multiplica por 2: 4, 8, 16, 32, 64."],
    "TPR811_2_10": ["¿Qué sigue en la fila? ★, ♦, ♦, ★, ♦, ♦, ★, ♦, ♦, ★, __", "Encuentra el grupo repetido.", ["★", "♦", "○", "□"], "El patrón se repite ★, ♦, ♦. La posición 11 es ♦."],
    "TPR811_2_11": ["¿Qué sigue? 5, 25, 125, __", "Multiplica por el mismo número cada vez.", ["150", "500", "250", "625"], "Cada número se multiplica por 5: 5, 25, 125, 625."],
    "TPR811_2_12": ["Cuadrícula: La fila 1 es 2, 4, 6. La fila 2 es 3, 6, 9. La fila 3 es 5, 10, __. ¿Cuál es el número que falta?", "Cada fila contiene múltiplos del primer número de esa fila.", ["12", "14", "15", "20"], "La fila 3 contiene múltiplos de 5: 5, 10, 15."],
    "TPR811_2_13": ["¿Qué sigue? 1, 4, 9, 16, __", "Son cuadrados perfectos: 1², 2², 3², 4²...", ["20", "25", "24", "36"], "Estos son números cuadrados: 1, 4, 9, 16, 25 (que tiene 1², 2², 3², 4², 5²)."],
    "TPR811_2_14": ["¿Qué sigue en la fila? A, A, B, A, A, B, A, A, B, __", "Encuentra el grupo repetido de 3.", ["un", "b", "c", "re"], "El patrón repite A, A, B. La posición 10 comienza un nuevo grupo que comienza con A."],
    "TPR811_2_15": ["¿Qué sigue? 1, 1, 2, 3, 5, 8, __", "Suma los dos números anteriores.", ["10", "11", "12", "13"], "Cada número es la suma de los dos anteriores: 5 + 8 = 13. Esta es la secuencia de Fibonacci."],
    "TPR811_2_16": ["Cuadrícula: La fila 1 es 1, 2, 3, 4. La fila 2 es 2, 4, 6, 8. La fila 3 es 4, 8, __, 16. ¿Cuál es el número que falta?", "Fila 3 = Fila 1 × 4.", ["10", "12", "14", "9"], "Fila 3 = Fila 1 × 4. Entonces 3 × 4 = 12."],
    "TPR811_2_17": ["¿Qué sigue? 10, 100, 1000, __", "Multiplica por 10 en cada paso.", ["1100", "2000", "10000", "5000"], "Cada número se multiplica por 10: 10, 100, 1000, 10000."],
    "TPR811_2_18": ["¿Qué sigue? 1, 3, 6, 10, __", "Mira las diferencias: +2, +3, +4…", ["13", "14", "15", "12"], "La diferencia aumenta en 1 en cada paso: +2, +3, +4, +5. Entonces 10 + 5 = 15. Estos son números triangulares."],
    "TPR811_2_19": ["¿Qué sigue? 1000, 500, 250, 125, __", "Cada número se divide por la mitad.", ["62,5", "100", "75", "60"], "Cada número es divisible por 2: 1000, 500, 250, 125, 62,5."],
    "TPR811_2_20": ["¿Qué sigue? 1, 8, 27, 64, __", "Estos son números cúbicos: 1³, 2³, 3³, 4³...", ["100", "81", "125", "216"], "Estos son números cúbicos: 1³=1, 2³=8, 3³=27, 4³=64, 5³=125."],
    "TPR811_3_01": ["¿Qué sigue? 1, 3, 7, 15, __", "Intenta multiplicar por 2 y luego sumar 1.", ["29", "30", "31", "23"], "Regla: ×2 luego +1. 1→3, 3→7, 7→15, 15→31."],
    "TPR811_3_02": ["¿Qué sigue? 2, 5, 11, 23, __", "Pruebe ×2 y luego +1.", ["35", "46", "47", "45"], "Regla: ×2 luego +1. 2→5, 5→11, 11→23, 23→47."],
    "TPR811_3_03": ["¿Qué sigue en la fila? ○, ○, □, △, ○, ○, □, △, ○, ○, __", "Encuentra el grupo de 4 símbolos repetidos.", ["○", "△", "□", "★"], "El patrón se repite: ○, ○, □, △. La posición 11 es □."],
    "TPR811_3_04": ["¿Qué sigue? 1, 4, 13, 40, __", "Pruebe ×3 y luego +1.", ["80", "121", "120", "81"], "Regla: ×3 luego +1. 1→4, 4→13, 13→40, 40→121."],
    "TPR811_3_05": ["Cuadrícula: La fila 1 es 1, 4, 7. La fila 2 es 3, 10, 17. La fila 3 es 5, 16, __. Cada fila sigue la misma regla de suma y la columna 1 tiene los valores 1, 3, 5. ¿Cuál es el número que falta?", "La fila 1 reúne 3 en cada paso. La fila 2 reúne 7 en cada paso. La fila 3 suma... mira los dos primeros números.", ["27", "25", "21", "23"], "Fila 3: 5, 16, 27. La diferencia es 11 en cada paso (5+11=16, 16+11=27)."],
    "TPR811_3_06": ["¿Qué sigue? 2, 6, 14, 30, __", "Pruebe ×2 y luego +2.", ["58", "60", "62", "56"], "Regla: ×2 luego +2. 2→6, 6→14, 14→30, 30→62."],
    "TPR811_3_07": ["¿Qué sigue? 3, 7, 15, 31, __", "Pruebe ×2 y luego +1.", ["47", "62", "63", "60"], "Regla: ×2 luego +1. 3→7, 7→15, 15→31, 31→63."],
    "TPR811_3_08": ["¿Qué sigue? 1, 2, 5, 10, 17, __", "Mira las diferencias entre los números: 1, 3, 5, 7...", ["24", "25", "26", "22"], "Las diferencias son números impares: +1, +3, +5, +7, +9. Entonces 17 + 9 = 26."],
    "TPR811_3_09": ["Cuadrícula: La fila 1 es 1, 4, 7. La fila 2 es 2, 8, 14. La fila 3 es 3, 12, __. ¿Cuál es el número que falta?", "Fila 2 = Fila 1 × 2. Fila 3 = Fila 1 ×?", ["18", "21", "15", "24"], "Fila 3 = Fila 1 × 3. Entonces 7 × 3 = 21."],
    "TPR811_3_10": ["¿Qué sigue? 0, 1, 3, 7, 15, __", "Pruebe ×2 y luego +1.", ["31", "30", "23", "29"], "Regla: ×2 luego +1. 0→1, 1→3, 3→7, 7→15, 15→31."],
    "TPR811_3_11": ["¿Qué sigue? 2, 3, 5, 9, 17, __", "Mira las diferencias: se duplican a cada paso.", ["25", "33", "31", "34"], "Las diferencias se duplican: +1, +2, +4, +8, +16. Entonces 17 + 16 = 33."],
    "TPR811_3_12": ["¿Qué sigue? 1, 2, 6, 24, __", "1×2=2, 2×3=6, 6×4=24, 24×?...", ["48", "120", "96", "30"], "Multiplica por números crecientes: ×2, ×3, ×4, ×5. Entonces 24 × 5 = 120."],
    "TPR811_3_13": ["Cuadrícula: La fila 1 es 2, 3, 4. La fila 2 es 5, 7, 9. La fila 3 es 11, 15, __. La regla entre filas es ×2 y luego +1. ¿Cuál es el número que falta?", "Aplica la regla a cada número en la fila 2.", ["17", "18", "19", "21"], "9 × 2 + 1 = 19."],
    "TPR811_3_14": ["¿Qué sigue? 100, 98, 94, 86, 70, __", "Mira cuánto se resta: 2, 4, 8, 16...", ["54", "38", "50", "42"], "Scadeiones dobles: −2, −4, −8, −16, −32. Entonces 70 − 32 = 38."],
    "TPR811_3_15": ["¿Qué sigue? 1, 4, 10, 22, __", "Pruebe ×2 y luego +2.", ["44", "46", "34", "40"], "Regla: ×2 luego +2. 1→4, 4→10, 10→22, 22→46."],
    "TPR811_3_16": ["¿Qué sigue? 5, 11, 23, 47, __", "Pruebe ×2 y luego +1.", ["94", "95", "93", "96"], "Regla: ×2 luego +1. 5→11, 11→23, 23→47, 47→95."],
    "TPR811_3_17": ["¿Qué sigue? 1, 2, 4, 7, 11, 16, __", "La diferencia aumenta en 1 en cada paso: +1, +2, +3, +4, +5...", ["21", "22", "20", "23"], "Diferencias: +1, +2, +3, +4, +5, +6. Entonces 16 + 6 = 22."],
    "TPR811_3_18": ["Columnas de cuadrícula: la columna 1 es 1, 2, 4. la columna 2 es 1, 3, 9. la columna 3 es 1, 4, __. ¿Cuál es el número que falta?", "la columna 1 son potencias de 2. la columna 2 son potencias de 3. la columna 3 son potencias de ?", ["8", "12", "16", "20"], "la columna 3 son potencias de 4: 4⁰=1, 4¹=4, 4²=16."],
    "TPR811_3_19": ["¿Qué sigue? 2, 5, 14, 41, __", "Pruebe ×3 y luego −1.", ["82", "122", "123", "124"], "Regla: ×3 luego −1. 2→5, 5→14, 14→41, 41→122."],
    "TPR811_3_20": ["¿Qué sigue? 1, 3, 9, 27, 81, __", "Cada número se multiplica por 3.", ["162", "243", "108", "100"], "Cada número es ×3: 1, 3, 9, 27, 81, 243."],
    "TNR811_1_01": ["¿Cuánto es 3 × 4?", "Piensa en 3 grupos de 4.", ["7", "10", "12", "14"], "3 × 4 = 12."],
    "TNR811_1_02": ["¿Cuánto es 5 × 6?", "Piensa en 5 grupos de 6.", ["25", "30", "35", "36"], "5 × 6 = 30."],
    "TNR811_1_03": ["¿Qué sigue? 5, 10, 15, 20, __", "Cuente de 5 a 5.", ["24", "25", "30", "22"], "Contando de 5 en 5: 5, 10, 15, 20, 25."],
    "TNR811_1_04": ["¿Cuál es el doble de 8?", "Doble significa ×2.", ["14", "16", "18", "10"], "Doble 8 = 8 × 2 = 16."],
    "TNR811_1_05": ["¿Cuánto cuesta 4 × 7?", "Piensa en 4 grupos de 7.", ["24", "21", "28", "32"], "4 × 7 = 28."],
    "TNR811_1_06": ["¿Qué sigue? 3, 6, 9, 12, __", "Cuente de 3 a 3.", ["13", "14", "15", "16"], "Contando de 3 en 3: 3, 6, 9, 12, 15."],
    "TNR811_1_07": ["¿Cuál es el doble de 15?", "Doble significa multiplicar por 2.", ["25", "28", "30", "35"], "Doble 15 = 15 × 2 = 30."],
    "TNR811_1_08": ["¿Cuánto es 5 × 8?", "Piensa en 5 grupos de 8.", ["35", "45", "40", "48"], "5 × 8 = 40."],
    "TNR811_1_09": ["Número de 4: 4, 8, 12, __, 20. ¿Cuánto falta?", "¿Cuánto es 12 + 4?", ["14", "16", "15", "18"], "Contando de 4 en 4: 4, 8, 12, 16, 20."],
    "TNR811_1_10": ["¿Cuánto es 3 × 9?", "Piensa en 3 grupos de 9.", ["24", "27", "21", "29"], "3 × 9 = 27."],
    "TNR811_1_11": ["¿Cuál es el doble de 25?", "Doble significa ×2.", ["45", "50", "55", "40"], "Doble 25 = 25 × 2 = 50."],
    "TNR811_1_12": ["¿Cuánto es 4 × 8?", "Piensa en 4 grupos de 8.", ["28", "30", "32", "36"], "4 × 8 = 32."],
    "TNR811_1_13": ["Número del 6: 6, 12, 18, __, 30. ¿Cuánto falta?", "¿Cuánto es 18 + 6?", ["22", "26", "24", "20"], "Contando de 6 en 6: 6, 12, 18, 24, 30."],
    "TNR811_1_14": ["¿Cuánto es 5 × 9?", "Piensa en 5 grupos de 9.", ["40", "50", "45", "54"], "5 × 9 = 45."],
    "TNR811_1_15": ["¿Cuál es el doble de 12?", "Doble significa ×2.", ["22", "24", "20", "26"], "Doble 12 = 12 × 2 = 24."],
    "TNR811_1_16": ["¿Cuánto es 3 × 7?", "Piensa en 3 grupos de 7.", ["18", "24", "21", "28"], "3 × 7 = 21."],
    "TNR811_1_17": ["Número de 3: 3, 6, 9, 12, 15, __. ¿Qué sigue?", "Recoge 3 en cada paso.", ["16", "17", "18", "19"], "Contando de 3 en 3: 3, 6, 9, 12, 15, 18."],
    "TNR811_1_18": ["¿Cuánto es 4 × 9?", "Piensa en 4 grupos de 9.", ["32", "36", "40", "27"], "4 × 9 = 36."],
    "TNR811_1_19": ["¿Cuál es el doble de 35?", "Doble significa ×2.", ["60", "65", "70", "75"], "Doble 35 = 35 × 2 = 70."],
    "TNR811_1_20": ["¿Cuánto es 5 × 7?", "Piensa en 5 grupos de 7.", ["30", "35", "40", "42"], "5 × 7 = 35."],
    "TNR811_2_01": ["¿Cuánto es la mitad de 48?", "La mitad significa ÷2.", ["20", "22", "24", "28"], "La mitad de 48 = 48 ÷ 2 = 24."],
    "TNR811_2_02": ["¿Cuál es el triple de 9?", "Triple significa ×3.", ["18", "27", "24", "21"], "Triple 9 = 9 × 3 = 27."],
    "TNR811_2_03": ["Cadena: 2, 4, 3, 6, 5, 10, 9, __. La regla se alterna: duplicar y luego restar 1. ¿Qué sigue?", "9 viene después de un paso de resta. ¿Qué operación sigue?", ["10", "18", "8", "12"], "El patrón alterna entre ×2 y −1. Después del 9 duplicamos: 9 × 2 = 18."],
    "TNR811_2_04": ["¿Cuánto es la mitad de 64?", "La mitad significa ÷2.", ["30", "34", "32", "36"], "La mitad de 64 = 64 ÷ 2 = 32."],
    "TNR811_2_05": ["¿Cuál es el triple de 12?", "Triple significa ×3.", ["24", "30", "36", "48"], "Triplicar 12 = 12 × 3 = 36."],
    "TNR811_2_06": ["Cadena: 1, 3, 2, 6, 5, 15, 14, __. La regla alterna: ×3, luego −1. ¿Qué sigue?", "14 viene después de restar 1. ¿Qué operación sigue a continuación?", ["13", "28", "42", "15"], "Alternancia: ×3 y −1. Después de 14 multiplicamos: 14 × 3 = 42."],
    "TNR811_2_07": ["¿Cuánto es la mitad de 100?", "La mitad significa ÷2.", ["40", "50", "55", "45"], "La mitad de 100 = 100 ÷ 2 = 50."],
    "TNR811_2_08": ["¿Cuál es el triple de 15?", "Triple significa ×3.", ["30", "40", "45", "60"], "Triplicar 15 = 15 × 3 = 45."],
    "TNR811_2_09": ["¿Qué sigue? 80, 40, 20, __", "Cada número se divide por la mitad.", ["15", "10", "5", "12"], "Cada número es divisible por 2: 80, 40, 20, 10."],
    "TNR811_2_10": ["¿Cuánto es la mitad de 36?", "La mitad significa ÷2.", ["16", "18", "20", "14"], "La mitad de 36 = 36 ÷ 2 = 18."],
    "TNR811_2_11": ["¿Cuál es el triple de 20?", "Triple significa ×3.", ["40", "50", "60", "80"], "Triplicar 20 = 20 × 3 = 60."],
    "TNR811_2_12": ["Cadena: 1, 2, 4, 5, 10, 11, 22, __. La regla alterna: +1, luego ×2. ¿Qué sigue?", "22 viene después de duplicar. ¿Qué operación sigue?", ["23", "24", "44", "32"], "Alternancia: +1 y ×2. Después de 22 sumamos 1: 22 + 1 = 23."],
    "TNR811_2_13": ["¿Cuánto es la mitad de 56?", "La mitad significa ÷2.", ["24", "26", "28", "30"], "La mitad de 56 = 56 ÷ 2 = 28."],
    "TNR811_2_14": ["¿Cuál es el triple de 8?", "Triple significa ×3.", ["16", "20", "24", "28"], "Triplicar 8 = 8 × 3 = 24."],
    "TNR811_2_15": ["¿Qué sigue? 96, 48, 24, 12, __", "Cada número se divide por la mitad.", ["8", "6", "10", "4"], "Todo número es divisible por 2: 96, 48, 24, 12, 6."],
    "TNR811_2_16": ["¿Cuánto es la mitad de 72?", "La mitad significa ÷2.", ["32", "34", "36", "38"], "La mitad de 72 = 72 ÷ 2 = 36."],
    "TNR811_2_17": ["¿Cuál es el triple de 25?", "Triple significa ×3.", ["50", "65", "75", "100"], "Triplicar 25 = 25 × 3 = 75."],
    "TNR811_2_18": ["Cadena: 5, 15, 10, 30, 25, 75, 70, __. La regla alterna: ×3, luego −5. ¿Qué sigue?", "70 viene después de restar 5. ¿Qué operación sigue?", ["65", "140", "210", "105"], "Alternancia: ×3 y −5. Después de 70 multiplicamos: 70 × 3 = 210."],
    "TNR811_2_19": ["¿Cuánto es la mitad de 84?", "La mitad significa ÷2.", ["38", "40", "42", "44"], "La mitad de 84 = 84 ÷ 2 = 42."],
    "TNR811_2_20": ["¿Cuál es el triple de 30?", "Triple significa ×3.", ["60", "90", "100", "120"], "Triplicar 30 = 30 × 3 = 90."],
    "TNR811_3_01": ["¿Qué sigue? 1, 3, 7, 15, 31, __", "Pruebe ×2 y luego +1.", ["47", "62", "63", "60"], "Regla: ×2 luego +1. 1→3, 3→7, 7→15, 15→31, 31→63."],
    "TNR811_3_02": ["¿Qué sigue? 2, 6, 18, 54, __", "Cada número es ×3.", ["108", "162", "72", "60"], "Cada número se multiplica por 3: 2, 6, 18, 54, 162."],
    "TNR811_3_03": ["¿Qué sigue? 100, 97, 91, 82, 70, __", "Mira las diferencias: −3, −6, −9, −12...", ["58", "55", "52", "60"], "Las diferencias aumentan en 3: −3, −6, −9, −12, −15. Entonces 70 − 15 = 55."],
    "TNR811_3_04": ["¿Qué sigue? 3, 4, 6, 10, 18, __", "Mira las diferencias: 1, 2, 4, 8... se duplican.", ["26", "34", "28", "36"], "Las diferencias se duplican: +1, +2, +4, +8, +16. Entonces 18 + 16 = 34."],
    "TNR811_3_05": ["¿Qué sigue? 2, 5, 11, 23, 47, __", "Pruebe ×2 y luego +1.", ["94", "95", "93", "96"], "Regla: ×2 luego +1. 2→5, 5→11, 11→23, 23→47, 47→95."],
    "TNR811_3_06": ["¿Qué sigue? 256, 128, 64, 32, __", "Cada número se divide por la mitad.", ["24", "16", "8", "20"], "Cada número es divisible por 2: 256, 128, 64, 32, 16."],
    "TNR811_3_07": ["¿Qué sigue? 1, 4, 13, 40, __", "Pruebe ×3 y luego +1.", ["80", "120", "121", "81"], "Regla: ×3 luego +1. 1→4, 4→13, 13→40, 40→121."],
    "TNR811_3_08": ["¿Qué sigue? 50, 46, 40, 32, 22, __", "Las diferencias aumentaron: −4, −6, −8, −10...", ["10", "12", "14", "8"], "Las diferencias aumentan en 2: −4, −6, −8, −10, −12. Entonces 22 − 12 = 10."],
    "TNR811_3_09": ["¿Qué sigue? 3, 9, 27, 81, __", "Cada número es ×3.", ["162", "243", "108", "100"], "Cada número se multiplica por 3: 3, 9, 27, 81, 243."],
    "TNR811_3_10": ["¿Qué sigue? 2, 3, 5, 9, 17, __", "Las diferencias se duplican: +1, +2, +4, +8...", ["25", "33", "34", "31"], "Las diferencias se duplican: +1, +2, +4, +8, +16. Entonces 17 + 16 = 33."],
    "TNR811_3_11": ["¿Qué sigue? 1, 5, 13, 29, __", "Pruebe ×2 y luego +3.", ["57", "58", "61", "45"], "Regla: ×2 luego +3. 1→5, 5→13, 13→29, 29→61."],
    "TNR811_3_12": ["¿Qué sigue? 200, 195, 185, 170, 150, __", "Las diferencias aumentaron: −5, −10, −15, −20...", ["130", "125", "120", "135"], "Las diferencias aumentan en 5: −5, −10, −15, −20, −25. Entonces 150 − 25 = 125."],
    "TNR811_3_13": ["¿Qué sigue? 4, 16, 64, 256, __", "Cada número es ×4.", ["512", "1024", "768", "640"], "Cada número se multiplica por 4: 4, 16, 64, 256, 1024."],
    "TNR811_3_14": ["¿Qué sigue? 1, 2, 6, 24, 120, __", "Multiplica por 2, luego por 3, luego por 4, luego por 5...", ["240", "600", "720", "360"], "×2, ×3, ×4, ×5, ×6. Entonces 120 × 6 = 720. Estos se llaman factoriales."],
    "TNR811_3_15": ["¿Qué sigue? 5, 8, 14, 26, 50, __", "Las diferencias se duplican: +3, +6, +12, +24...", ["74", "98", "76", "100"], "Las diferencias se duplican: +3, +6, +12, +24, +48. Entonces 50 + 48 = 98."],
    "TNR811_3_16": ["¿Qué sigue? 3, 10, 31, 94, __", "Pruebe ×3 y luego +1.", ["188", "282", "283", "281"], "Regla: ×3 luego +1. 3→10, 10→31, 31→94, 94→283."],
    "TNR811_3_17": ["¿Qué sigue? 80, 77, 71, 62, 50, __", "Las diferencias aumentaron: −3, −6, −9, −12...", ["35", "38", "40", "42"], "Las diferencias aumentan en 3: −3, −6, −9, −12, −15. Entonces 50 − 15 = 35."],
    "TNR811_3_18": ["¿Qué sigue? 1, 2, 4, 8, 16, 32, __", "Cada número se duplica.", ["48", "60", "64", "36"], "Cada número es ×2: 1, 2, 4, 8, 16, 32, 64."],
    "TNR811_3_19": ["¿Qué sigue? 2, 7, 22, 67, __", "Pruebe ×3 y luego +1.", ["134", "200", "201", "202"], "Regla: ×3 luego +1. 2→7, 7→22, 22→67, 67→202."],
    "TNR811_3_20": ["¿Qué sigue? 1000, 990, 970, 940, 900, __", "Las diferencias aumentaron: −10, −20, −30, −40...", ["860", "850", "840", "870"], "Las diferencias aumentan en 10: −10, −20, −30, −40, −50. Entonces 900 − 50 = 850."],
    "TLR811_1_01": ["Todos los perros son animales. Spot es un perro. ¿Qué es el punto?", "Si Spot es un perro y todos los perros son animales...", ["una planta", "un animal", "un pájaro", "un pez"], "Todos los perros son animales. Spot es un perro. Entonces Spot es un animal."],
    "TLR811_1_02": ["Todas las manzanas son frutas. Todas las frutas son alimento. ¿Se sigue de ello que todas las manzanas son alimento?", "La cadena es la siguiente: manzanas → fruta → comida.", ["si", "No", "solo algunos", "no podemos saber"], "Las manzanas son frutas y la fruta es alimento. Entonces todas las manzanas son alimento."],
    "TLR811_1_03": ["Tom es más alto que Sam. Sam es más alto que Ben. ¿Quién es el más alto?", "Ponlos en orden de altura.", ["Sam", "ben", "tom", "soy el mismo"], "Tom > Sam > Ben. Tom es el más alto."],
    "TLR811_1_04": ["Todos los gatos tienen cola. Bigotes es un gato. ¿Los bigotes tienen cola?", "Si todos los gatos tienen cola y Bigotes es un gato...", ["si", "No", "tal vez", "Sólo a veces"], "Todos los gatos tienen cola. Bigotes es un gato. Entonces Bigote tiene cola."],
    "TLR811_1_05": ["Ana es mayor que Ben. Ben es mayor que Cara. ¿Quién es el más joven?", "Ordénalos de mayor a menor.", ["ana", "ben", "Cara", "tienen la misma edad"], "Ana > Ben > Cara según la edad. Cara es la más joven."],
    "TLR811_1_06": ["Todas las aves tienen plumas. Una golondrina es un pájaro. ¿La golondrina tiene plumas?", "Si todos los pájaros tienen plumas...", ["No", "si", "solo en invierno", "tal vez"], "Todas las aves tienen plumas. La golondrina es un pájaro. Entonces tiene plumas."],
    "TLR811_1_07": ["El rojo es más grande que el azul. El azul es más grande que el verde. ¿Cuál es el más pequeño?", "Ordenarlos por tamaño.", ["rojo", "azul", "Verde", "son iguales"], "Rojo > Azul > Verde. El verde es el más pequeño."],
    "TLR811_1_08": ["Todos los peces viven en el agua. Un pez dorado es un pez. ¿Dónde vive un pez dorado?", "Si todos los peces vivieran en el agua...", ["En tierra firme", "en los arboles", "en el agua", "en el cielo"], "Todos los peces viven en el agua. Los peces de colores son peces. Entonces vive en el agua."],
    "TLR811_1_09": ["El libro A tiene más páginas que el libro B. El libro B tiene más páginas que el libro C. ¿Cuál tiene menos páginas?", "Ordena los libros por número de páginas.", ["Libro A", "Libro B", "Libro C", "son iguales"], "A > B > C a páginas. El libro C tiene la menor cantidad de páginas."],
    "TLR811_1_10": ["Todos los cuadrados tienen 4 lados. Esta forma es un cuadrado. ¿Cuantos lados tiene?", "Si es cuadrado...", ["3", "4", "5", "6"], "Todos los cuadrados tienen 4 lados. Esta forma es cuadrada. Entonces tiene 4 lados."],
    "TLR811_1_11": ["La pizza es más barata que el bistec. El filete es más barato que la langosta. ¿Cuál es el más barato?", "Ordenarlos por precio.", ["filete", "la langosta", "pizzería", "cuesta lo mismo"], "Pizza < Filete < Langosta a un precio. La pizza es la más barata."],
    "TLR811_1_12": ["Todas las rosas son flores. Todas las flores son plantas. ¿Es la rosa una planta?", "La cadena es la siguiente: rosas → flores → plantas.", ["si", "No", "tal vez", "Solo rosas rojas"], "Las rosas son flores y las flores son plantas. Entonces la rosa es una planta."],
    "TLR811_1_13": ["El equipo A anotó más que el equipo B. El equipo B anotó más que el equipo C. ¿Quién anotó más?", "Clasificar equipos por puntuación.", ["Equipo C", "Equipo B", "Equipo A", "Igualdad"], "A > B > C en la partitura. El equipo A anotó más."],
    "TLR811_1_14": ["Todas las monedas son redondas. Un centavo es una moneda. ¿Qué forma tiene un centavo?", "Si todas las monedas son redondas...", ["cuadrado", "Triangulo", "redondo", "Ovalado"], "Todas las monedas son redondas. El centavo es moneda. Entonces es redondo."],
    "TLR811_1_15": ["Mia corre más rápido que Lily. Lily corre más rápido que Zoe. ¿Quién es el más lento?", "Ordenarlos por velocidad.", ["Mía", "lirio", "Zoé", "soy el mismo"], "Mia > Lily > Zoe a toda velocidad. Zoe es la más lenta."],
    "TLR811_1_16": ["Todos los triángulos tienen 3 lados. Esta forma tiene 3 lados. ¿Puede ser un triángulo?", "Los triángulos tienen 3 lados. ¿Significa esto necesariamente que la forma es un triángulo?", ["Si, puede ser", "No, nunca", "Sólo si es grande", "Solo si es rojo"], "Todos los triángulos tienen 3 lados, y esta figura tiene 3 lados, por lo que puede ser un triángulo."],
    "TLR811_1_17": ["Un elefante pesa más que un caballo. Un caballo pesa más que un perro. ¿Cuál es el más fácil?", "Clasifícalos por peso.", ["el elefante", "el caballo", "el perro", "yo canto lo mismo"], "Elefante > Caballo > Perro por peso. El perro es el más fácil."],
    "TLR811_1_18": ["Todos los lápices pueden escribir. Este es un lápiz. ¿Puede escribir?", "Si todos los lápices pudieran escribir...", ["si", "No", "Sólo a veces", "no lo sabemos"], "Todos los lápices pueden escribir. Este es un lápiz. Para que pueda escribir."],
    "TLR811_1_19": ["La caja A es más ancha que la caja B. La caja B es más ancha que la caja C. ¿Cuál es más ancha?", "Ordenar cuadros por ancho.", ["Cuadro C", "Cuadro B", "Cuadro A", "soy el mismo"], "A > B > C en ancho. El cuadro A es el más ancho."],
    "TLR811_1_20": ["Todo el helado está frío. Esto es helado. ¿Hace frío?", "Si todo el helado está frío…", ["No", "tal vez", "si", "solo en invierno"], "Todo el helado está frío. Esto es helado. Entonces hace frío."],
    "TLR811_2_01": ["Todo el chocolate es dulce. Este caramelo es dulce. ¿Es el chocolate SEGURO?", "Sólo porque todo el chocolate es dulce, ¿significa eso que todo lo dulce es chocolate?", ["si, seguro", "No, no necesariamente", "Solo chocolate amargo", "siempre"], "Todo el chocolate es dulce, pero otras cosas también pueden serlo. No es necesariamente chocolate."],
    "TLR811_2_02": ["Anna es más alta que Ben. Ben es más alto que Cara. Cara es más alta que Dan. ¿Quién es el segundo más alto?", "Pon los cuatro en orden de altura.", ["ana", "ben", "Cara", "Dan"], "Anna > Ben > Cara > Dan. Ben es el segundo más alto."],
    "TLR811_2_03": ["Todos los coches tienen ruedas. Este vehículo tiene ruedas. ¿Es un coche SEGURO?", "¿Solo los coches tienen ruedas?", ["si", "No, no necesariamente", "Solo si es rojo", "siempre"], "Muchos vehículos tienen ruedas (bicicletas, autobuses, camiones). No es necesariamente un coche."],
    "TLR811_2_04": ["El rojo es más grande que el azul. El azul es más grande que el verde. El verde es más grande que el amarillo. ¿Cuál es el tercero más grande?", "Ordena los cuatro por tamaño.", ["rojo", "azul", "Verde", "amarillo"], "Rojo > Azul > Verde > Amarillo. El verde es el tercero más grande."],
    "TLR811_2_05": ["Todos los cuadrados son rectángulos. Esta forma es un rectángulo. ¿Es SEGURO cuadrado?", "Todos los cuadrados son rectángulos, pero ¿todos los rectángulos son cuadrados?", ["si", "No, no necesariamente", "Solo si es pequeño", "siempre"], "Todos los cuadrados son rectángulos, pero no todos los rectángulos son cuadrados. Puede que no sea cuadrado."],
    "TLR811_2_06": ["Kim obtuvo 90 puntos. Lee 85. Min 95. Pat 80. ¿Quién quedó segundo?", "Ordenar de mayor a menor puntuación.", ["kim", "Lee", "mín.", "cama"], "Min (95) > Kim (90) > Lee (85) > Pat (80). Kim fue segunda."],
    "TLR811_2_07": ["Todos los perros ladran. Un animal ladra. ¿Es SEGURO para perros?", "¿Solo ladran los perros?", ["si, seguro", "No, no necesariamente", "Sólo los perros grandes ladran.", "siempre"], "Otros animales también pueden ladrar (por ejemplo, las focas). No es necesariamente un perro."],
    "TLR811_2_08": ["El libro A tiene 200 páginas. B es 150. C es 300. D es 250. ¿Cuál es el tercero más largo?", "Ordene de más a menos páginas.", ["Libro A", "Libro B", "Libro C", "Libro D"], "C (300) > D (250) > A (200) > B (150). El libro A es el tercero más largo."],
    "TLR811_2_09": ["Todos los números pares son exactamente divisibles por 2. El número 15 no es exactamente divisible por 2. ¿Qué podemos decir del 15?", "Si no es divisible por 2, ¿puede ser par?", ["es incluso", "no es pelo", "no podemos saber", "puede ser incluso"], "Todos los números pares son divisibles por 2. 15 no es divisible por 2. Entonces 15 no es par."],
    "TLR811_2_10": ["Amy, Ben, Cat y Dan corren. Amy vence a Ben. Cat supera a Amy. Dan vence a Cat. ¿Quién va ganando?", "Si Dan vence a Cat y Cat vence a Amy...", ["amy", "ben", "gato", "Dan"], "Dan > Gato > Amy > Ben. Dan gana."],
    "TLR811_2_11": ["Todas las bicicletas tienen 2 ruedas. Este vehículo tiene 2 ruedas. ¿Es la bicicleta SEGURA?", "¿Solo las bicicletas tienen 2 ruedas?", ["si", "No, no necesariamente", "Solo bicicletas de montaña.", "siempre"], "Y los scooters, las motos tienen 2 ruedas. No es necesariamente una bicicleta."],
    "TLR811_2_12": ["Cuatro amigos tienen puntuaciones diferentes: 70, 80, 90, 100. James obtuvo más de 80 pero menos de 100. ¿Cuál fue su puntuación?", "¿Qué puntuación está entre 80 y 100?", ["70", "80", "90", "100"], "La única puntuación entre 80 y 100 es 90."],
    "TLR811_2_13": ["Todas las arañas tienen 8 patas. Esta criatura tiene 8 patas. ¿Es una araña SEGURA?", "¿Solo las arañas tienen 8 patas?", ["si", "No, no necesariamente", "solo los grandes", "siempre"], "Y los escorpiones tienen 8 patas. 8 patas no necesariamente significan una araña."],
    "TLR811_2_14": ["El roble es más alto que el abedul. El pino es más alto que el roble. El olmo es más bajo que el abedul. ¿Qué árbol es el más alto?", "Coloca los cuatro árboles.", ["el roble", "el abedul", "el pino", "el olmo"], "Pino > Roble > Abedul > Olmo. El pino es el más alto."],
    "TLR811_2_15": ["Todos los planetas orbitan alrededor de una estrella. La Tierra orbita una estrella. ¿Esto prueba que la Tierra es un planeta?", "¿Sólo los planetas orbitan alrededor de las estrellas?", ["Si, lo demuestra", "No, no lo prueba", "Sólo a veces", "siempre"], "Y los cometas, los asteroides orbitan alrededor de estrellas. La órbita por sí sola no prueba que sea un planeta."],
    "TLR811_2_16": ["Sam tiene más pegatinas que Mia. Mia tiene más que Jo. Jo tiene más que Lee. ¿Quién tiene menos?", "Pídelos.", ["Sam", "Mía", "Jo", "Lee"], "Sam > Mia > Jo > Lee. Lee tiene la menor cantidad."],
    "TLR811_2_17": ["Si llueve, el suelo está mojado. El suelo está mojado. ¿Está lloviendo SEGURO?", "¿El suelo podría estar mojado por otras razones?", ["si, seguro", "No, no necesariamente", "solo en verano", "siempre"], "Alguien podría haberlo limpiado con una manguera. El suelo mojado no demuestra lluvia."],
    "TLR811_2_18": ["El gato pesa menos que el perro. El perro menos que la oveja. La oveja menos que la vaca. ¿Qué animal pesa más?", "Ordenar por peso.", ["el gato", "el perro", "la oveja", "la vaca"], "Gato < Perro < Oveja < Vaca. La vaca es la que más pesa."],
    "TLR811_2_19": ["Todas las manzanas son frutas. Esto NO es fruta. ¿Puede ser manzana?", "Si todas las manzanas son frutas y ésta no es fruta...", ["si", "No, no puede", "tal vez", "Solo los verdes"], "Todas las manzanas son frutas. Si no es fruta, no puede ser manzana."],
    "TLR811_2_20": ["Cuatro niños tienen 8, 9, 10, 11 años. Kai es más grande que Zoe. Zoé que Leo. Leo que Ivy. cuantos años tiene zoe", "Kai es la mayor, luego Zoe, Leo e Ivy.", ["8", "9", "10", "11"], "Kai=11, Zoe=10, Leo=9, Ivy=8. Zoé tiene 10 años."],
    "TLR811_3_01": ["Si llueve, Tom lleva un paraguas. Si toma un paraguas, se mantiene seco. Está lloviendo. ¿Tom permanecerá seco?", "La cadena sigue: lluvia → paraguas → seco.", ["si", "No", "tal vez", "Solo si hace frio"], "Lluvia → paraguas → seco. Está lloviendo, así que Tom se mantiene seco."],
    "TLR811_3_02": ["Si A es verdadera, entonces B es verdadera. B NO es cierto. ¿Es A cierto?", "Si A siempre hiciera que B fuera verdadero y B falso...", ["si", "No", "tal vez", "no podemos saber"], "Si A fuera cierto, B debería serlo. Pero B no lo es. Entonces A no puede ser verdadero."],
    "TLR811_3_03": ["Hoy es miércoles. ¿Qué día fue hace 3 días?", "Cuenta atrás: martes, lunes, domingo.", ["lunes", "domingo", "sábado", "martes"], "Miércoles −1 = martes, −2 = lunes, −3 = domingo."],
    "TLR811_3_04": ["Si estudias, apruebas el examen. Si pasas la prueba, obtienes la recompensa. Maya aprendió. ¿Maya recibe su recompensa?", "La cadena es la siguiente: aprender → aprobar la prueba → recompensa.", ["si", "No", "Sólo a veces", "no podemos saber"], "Aprender → pasar → recompensa. Maya aprendió, por eso recibe la recompensa."],
    "TLR811_3_05": ["Si Anna nada, usa gafas de natación. Anna NO usa gafas. ¿Anna nada?", "Si siempre usa gafas cuando nada, y ahora no...", ["si", "No", "tal vez", "solo lunes"], "Si estuviera nadando, usaría gafas. No lleva, por lo que no nada."],
    "TLR811_3_06": ["Hoy es 28 de marzo. ¿Qué fecha es dentro de 5 días?", "Marzo tiene 31 días. Cuente hacia adelante desde 28.", ["33 de marzo", "1 de abril", "2 de abril", "3 de abril"], "Marzo tiene 31 días. 28 + 5 = 33. 33 − 31 = 2. Entonces es 2 de abril."],
    "TLR811_3_07": ["Si Max come pastel, se enferma. Max NO está herido. ¿Max comió pastel?", "Si la tarta siempre le pone mal, y ahora ya no...", ["si", "No", "tal vez", "Solo pastel de chocolate"], "Si comiera pastel, se enfermaría. No le apetece, así que no comió."],
    "TLR811_3_08": ["Si A lleva a B, B a C, C a D. ¿Sucede A? ¿Ocurre D?", "Sigue la cadena de A a D.", ["si", "No", "Sólo a veces", "no podemos saber"], "A → B → C → D. Si A, entonces D."],
    "TLR811_3_09": ["Es octubre. ¿Cuántos meses faltan para marzo (contando hacia arriba)?", "Número: noviembre, diciembre, enero, febrero, marzo.", ["4", "5", "6", "3"], "noviembre (1), diciembre (2), enero (3), febrero (4), marzo (5). Son 5 meses."],
    "TLR811_3_10": ["Si una figura tiene 4 lados iguales y 4 ángulos rectos, es cuadrada. Esta forma NO tiene 4 lados iguales. ¿Seguro que NO es cuadrado?", "¿Puede ser un cuadrado sin 4 lados iguales?", ["Si, no es cuadrado", "No, todavía podría ser cuadrado.", "tal vez", "Sólo si es grande"], "El cuadrado debe tener 4 lados iguales. Si no los tiene, no es cuadrado."],
    "TLR811_3_11": ["Si presionas el botón, la luz se enciende. Si se enciende la luz, suena el timbre. Presionaste el botón. que esta pasando", "La cadena sigue: botón → luz → campana.", ["nada", "solo la luz", "Suena la campana", "El botón se rompe"], "Botón → luz → campana. Presionaste, entonces suena el timbre."],
    "TLR811_3_12": ["Hoy es viernes. ¿Qué día será dentro de 10 días?", "10 = 7 + 3. Una semana entera más 3 días.", ["domingo", "lunes", "martes", "miércoles"], "10 días = 1 semana + 3 días. Viernes + 3 = lunes."],
    "TLR811_3_13": ["Todos los estudiantes de la clase A juegan al fútbol. Tom NO juega al fútbol. ¿Tom está en la clase A?", "Si todos en A juegan al fútbol y Tom no...", ["si", "No", "tal vez", "Sólo los fines de semana"], "Todos en A juegan al fútbol. Tom no juega, por lo que no está en la clase A."],
    "TLR811_3_14": ["Si nieva, la escuela está cerrada. Si la escuela está cerrada, los niños juegan afuera. NO nevó. ¿Podemos estar SEGUROS de que los niños NO están jugando afuera?", "¿Podría la escuela cerrar por otro motivo?", ["Si, estamos seguros", "No, no podemos estar seguros", "solo en verano", "siempre"], "La escuela también puede cerrar por otros motivos (vacaciones, reparaciones). Los niños todavía podían jugar afuera."],
    "TLR811_3_15": ["Hoy es 30 de noviembre. ¿Qué fecha es dentro de 3 días?", "Noviembre tiene 30 días; ¿Qué sigue después del 30 de noviembre?", ["33 de noviembre", "1 de diciembre", "2 de diciembre", "3 de diciembre"], "Noviembre tiene 30 días. 30 de noviembre +1 = 1 de diciembre, +2 = 2 de diciembre, +3 = 3 de diciembre"],
    "TLR811_3_16": ["X es mayor que Y. Y que Z. Z que W. W que V. ¿Cuál es más grande?", "¿Quién está en la cima de la cadena?", ["V", "w", "Y", "x"], "X > Y > Z > W > V. X es el más grande."],
    "TLR811_3_17": ["Todos los peces pueden nadar. Algo no puede nadar. es pescado", "Si todos los peces nadan y este no...", ["si", "No", "tal vez", "Sólo peces pequeños"], "Todos los peces nadan. Si no sabe nadar, no es un pez."],
    "TLR811_3_18": ["Hoy es martes. ¿Qué día será dentro de 25 días?", "25 ÷ 7 = 3 semanas y 4 días extra.", ["viernes", "sábado", "domingo", "lunes"], "25 = 3 semanas + 4 días. Martes + 4 = Sábado."],
    "TLR811_3_19": ["Si A es verdadera, B debe ser verdadera. Si B es verdadera, C debe ser verdadera. C NO es cierta. ¿Es A cierto?", "Funciona al revés: si C es falso, ¿qué pasa con B? Entonces con A?", ["si", "No", "tal vez", "no podemos saber"], "Si A → B → C. C es falso, entonces B es falso, entonces A es falso."],
    "TLR811_3_20": ["Todo gato es peludo. Todo lo peludo es suave. Cualquier cosa suave es agradable de abrazar. Bigotes es un gato. ¿Es lindo abrazar a Bigotes?", "La cadena sigue: gato → peludo → suave → abrazable.", ["si", "No", "tal vez", "solo los gatitos"], "Gato → peludo → suave → agradable. Bigotes es un gato, por eso es agradable abrazarlo."],
    "TSR811_1_01": ["¿Cuántas caras tiene un cubo?", "Piensa en un dado: cuenta las caras planas.", ["4", "6", "8", "12"], "Un cubo tiene 6 caras planas."],
    "TSR811_1_02": ["¿Cuántas aristas tiene un cubo?", "Una arista es el lugar donde se encuentran dos caras. Cuente todos los bordes.", ["6", "8", "10", "12"], "Un cubo tiene 12 aristas."],
    "TSR811_1_03": ["¿Cuántos vértices (esquinas) tiene un cubo?", "Un vértice es el punto donde se encuentran las aristas.", ["4", "6", "8", "12"], "Un cubo tiene 8 vértices (esquinas)."],
    "TSR811_1_04": ["¿Qué forma tiene cada cara de un cubo?", "Todas las caras del cubo tienen la misma forma.", ["Triangulo", "Rectángulo", "cuadrado", "circulo"], "Cada cara de un cubo es un cuadrado."],
    "TSR811_1_05": ["¿Cuántas caras tiene una caja rectangular (cuboide)?", "Piensa en una caja de zapatos. Cuente las caras planas.", ["4", "5", "6", "8"], "Un cuboide (caja rectangular) tiene 6 caras."],
    "TSR811_1_06": ["¿Cuántas caras planas tiene una esfera?", "Una esfera es como una pelota.", ["0", "1", "2", "4"], "Una esfera tiene 0 caras planas. Es completamente redondeado."],
    "TSR811_1_07": ["¿Cuántas caras planas tiene un cilindro?", "Piensa en una lata. ¿Qué lados planos tiene?", ["0", "1", "2", "3"], "Un cilindro tiene 2 caras planas (círculo superior y círculo inferior)."],
    "TSR811_1_08": ["¿Qué figura 3D tiene 6 caras cuadradas todas iguales?", "Todas las caras son cuadrados idénticos.", ["cuboide", "cubos", "prisma", "pirámide"], "Un cubo tiene 6 caras cuadradas idénticas."],
    "TSR811_1_09": ["¿Cuántas caras planas tiene un cono?", "Piensa en un cono de helado. Tiene una única base plana.", ["0", "1", "2", "3"], "Un cono tiene 1 cara plana (base circular)."],
    "TSR811_1_10": ["¿Cuántas aristas tiene una pirámide triangular (tetraedro)?", "Tiene 4 caras triangulares. Cuenta dónde se encuentran los triángulos.", ["4", "5", "6", "8"], "Una pirámide triangular (tetraedro) tiene 6 aristas."],
    "TSR811_1_11": ["Si miras un cubo directamente de frente, ¿qué forma ves?", "Vea una cara del cubo frontal.", ["Triangulo", "circulo", "cuadrado", "Rectángulo"], "Si miras directamente a una de las caras de un cubo, verás un cuadrado."],
    "TSR811_1_12": ["¿Cuántas caras tiene un prisma triangular?", "Piense en una caja de Toblerone: 2 triángulos y algunos rectángulos.", ["3", "4", "5", "6"], "Un prisma triangular tiene 5 caras: 2 triángulos y 3 rectángulos."],
    "TSR811_1_13": ["¿Cuántos vértices tiene una pirámide triangular (tetraedro)?", "Cuente las esquinas afiladas.", ["3", "4", "5", "6"], "Una pirámide triangular tiene 4 vértices."],
    "TSR811_1_14": ["¿Qué forma tiene la base de un cono?", "La base plana de un cono es...", ["cuadrado", "Triangulo", "circulo", "Ovalado"], "La base de un cono es un círculo."],
    "TSR811_1_15": ["¿Cuántas aristas tiene un cuboide?", "Un cuboide es como un cubo, pero con caras rectangulares. Cuente los bordes.", ["8", "10", "12", "14"], "Un cuboide tiene 12 aristas, al igual que un cubo."],
    "TSR811_1_16": ["¿Cuántas caras tiene una pirámide de base cuadrada?", "Tiene una base cuadrada y caras laterales triangulares.", ["4", "5", "6", "8"], "Una pirámide de base cuadrada tiene 5 caras: 1 base cuadrada y 4 triángulos."],
    "TSR811_1_17": ["Si apilas 2 cubos uno encima del otro, la forma combinada se parece más a un...", "Dos cubos apilados forman una forma más alta.", ["cubos", "Esferas", "cuboide", "Cilindro"], "Dos cubos apilados forman un paralelepípedo (caja rectangular)."],
    "TSR811_1_18": ["¿Cuántos vértices tiene un cuboide?", "Cuenta todas las esquinas de una caja rectangular.", ["4", "6", "8", "10"], "Un cuboide tiene 8 vértices, al igual que un cubo."],
    "TSR811_1_19": ["¿Cuántas superficies curvas tiene una esfera?", "Una esfera es perfectamente redonda en todas partes.", ["0", "1", "2", "4"], "Una esfera tiene 1 superficie curva."],
    "TSR811_1_20": ["¿Cuántas caras tiene un prisma hexagonal?", "Tiene 2 extremos hexagonales y caras laterales rectangulares. El hexágono tiene 6 lados.", ["6", "7", "8", "10"], "Un prisma hexagonal tiene 8 caras: 2 hexágonos + 6 rectángulos."],
    "TSR811_2_01": ["Si cortas un cubo exactamente por la mitad, paralelo a una de las caras, ¿qué forma tiene la sección?", "Cortar recto, como cortar pan.", ["Triangulo", "circulo", "cuadrado", "Rectángulo"], "Cortar el cubo paralelo a una cara te dará una sección de forma cuadrada."],
    "TSR811_2_02": ["8 cubos pequeños forman un cubo de 2×2×2. ¿Cuántos cubos pequeños están completamente ocultos (sin caras visibles)?", "En la disposición de 2×2×2, cada cubo está en el exterior.", ["0", "1", "2", "4"], "En el cubo de 2×2×2, cada cubo pequeño está en la esquina con caras visibles. Ninguno está oculto."],
    "TSR811_2_03": ["¿Cuántas aristas tiene un prisma triangular?", "3 bordes en el triángulo superior + 3 en la parte inferior + 3 que los conectan.", ["6", "8", "9", "12"], "Un prisma triangular tiene 9 aristas: 3 + 3 + 3."],
    "TSR811_2_04": ["Alineas 3 cubos uno tras otro, uno frente al otro. ¿Cuántas caras de los cubos pequeños están ocultas (tocando otro cubo)?", "Donde los cubos se tocan, se ocultan 2 caras en cada unión.", ["2", "3", "4", "6"], "Hay 2 articulaciones. Cada uno esconde 2 caras. Total de caras ocultas: 2 × 2 = 4."],
    "TSR811_2_05": ["¿Cuántas aristas tiene una pirámide con base cuadrada?", "4 bordes en la base + 4 hacia arriba.", ["5", "6", "8", "10"], "Una pirámide de base cuadrada tiene 8 aristas: 4 en la base + 4 en los lados."],
    "TSR811_2_06": ["Si cortas un cilindro por la mitad (perpendicular a la altura), ¿qué forma tiene la sección?", "Cortar como un tronco, perpendicular al eje.", ["cuadrado", "Rectángulo", "circulo", "Ovalado"], "Al cortar el cilindro perpendicular a la altura se obtiene un círculo."],
    "TSR811_2_07": ["27 cubos pequeños forman un cubo de 3×3×3. ¿Cuántos cubos pequeños tienen al menos una cara visible en el exterior?", "Sólo el cubo en el centro exacto está completamente oculto.", ["24", "25", "26", "27"], "Sólo 1 cubo (el del centro) está oculto. 27 − 1 = 26 cubos tienen al menos una cara visible."],
    "TSR811_2_08": ["¿Cuántas caras tiene un prisma pentagonal?", "2 cabezas pentagonales + caras rectangulares. El pentágono tiene 5 lados.", ["5", "6", "7", "8"], "Un prisma pentagonal tiene 7 caras: 2 pentágonos + 5 rectángulos."],
    "TSR811_2_09": ["¿Cuántos vértices tiene una pirámide de base cuadrada?", "4 esquinas en la base + 1 punto en la parte superior.", ["4", "5", "6", "8"], "Una pirámide de base cuadrada tiene 5 vértices: 4 en la base + 1 vértice."],
    "TSR811_2_10": ["Se colocan 4 cubos en una sola capa cuadrada de 2 × 2. ¿Cuántas caras se pueden ver desde arriba?", "Cada cubo muestra 1 boca arriba.", ["2", "3", "4", "8"], "Cada uno de los 4 cubos muestra 1 boca arriba. Total = 4 boca arriba."],
    "TSR811_2_11": ["¿Cuántas caras tiene una pirámide hexagonal?", "1 base hexagonal + caras laterales triangulares. El hexágono tiene 6 lados.", ["6", "7", "8", "9"], "Una pirámide hexagonal tiene 7 caras: 1 hexágono + 6 triángulos."],
    "TSR811_2_12": ["Si cortas un cubo desde un borde hasta el borde opuesto (en diagonal por el medio), la sección es un...", "El corte es diagonal pero permanece plano.", ["Triangulo", "cuadrado", "Rectángulo", "circulo"], "Cortar de un borde al opuesto le dará una sección rectangular."],
    "TSR811_2_13": ["¿Cuántas caras tiene una pirámide triangular (tetraedro)?", "Todas sus caras son triángulos.", ["3", "4", "5", "6"], "Una pirámide triangular tiene 4 caras triangulares."],
    "TSR811_2_14": ["8 cubos forman un cubo de 2×2×2. ¿Cuántas caras de los cubos pequeños son visibles en el exterior del cubo grande?", "El cubo grande tiene 6 caras, cada una de las cuales consta de 4 caras pequeñas.", ["16", "20", "24", "32"], "6 caras grandes × 4 caras pequeñas cada una = 24 caras pequeñas visibles."],
    "TSR811_2_15": ["¿Cuántos vértices tiene una pirámide de base pentagonal?", "5 esquinas en la base + 1 punto en la parte superior.", ["5", "6", "7", "10"], "Una pirámide pentagonal tiene 6 vértices: 5 en la base + 1 en el vértice."],
    "TSR811_2_16": ["¿Cuántas aristas tiene un prisma hexagonal?", "6 arriba + 6 abajo + 6 conectándolos.", ["12", "14", "16", "18"], "Un prisma hexagonal tiene 18 aristas: 6 + 6 + 6."],
    "TSR811_2_17": ["Retire un cubo de esquina de una disposición de 2 × 2 × 2. ¿Cuántos cubos pequeños quedan?", "Tienes 8 cubos pequeños y retiras 1.", ["5", "6", "7", "4"], "8 − 1 = quedan 7 cubos."],
    "TSR811_2_18": ["¿Cuántos vértices tiene un prisma triangular?", "3 esquinas en cada extremo triangular.", ["4", "5", "6", "8"], "Un prisma triangular tiene 6 vértices: 3 en cada triángulo."],
    "TSR811_2_19": ["Si pintas todas las caras de un cubo de 2×2×2 y lo desdoblas, ¿cuántos cubos pequeños tienen exactamente 3 caras pintadas?", "En el cubo de 2×2×2, cada cubo pequeño está en la esquina.", ["4", "6", "8", "0"], "Los 8 cubos de 2×2×2 son esquinas, por lo que los 8 tienen exactamente 3 caras pintadas."],
    "TSR811_2_20": ["¿Cuántas caras tiene un prisma octogonal?", "2 extremos octogonales + caras rectangulares. El octágono tiene 8 lados.", ["8", "10", "12", "16"], "Un prisma octogonal tiene 10 caras: 2 octágonos + 8 rectángulos."],
    "TSR811_3_01": ["¿Cuántos cuadrados se despliega un cubo (la versión desplegada)?", "Cada cara del cubo se convierte en un cuadrado que se despliega.", ["4", "5", "6", "8"], "Un cubo tiene 6 caras, por lo que desplegado tiene 6 cuadrados."],
    "TSR811_3_02": ["En un cubo de 3×3×3 de 27 cubos pequeños, ¿cuántos cubos están completamente ocultos (sin cara visible)?", "Sólo el cubo en el centro exacto no mira hacia afuera.", ["0", "1", "4", "8"], "Sólo 1 cubo, el que está exactamente en el centro, está completamente oculto."],
    "TSR811_3_03": ["Cuando doblas una cruz desplegada (como un plus de 6 cuadrados), ¿qué forma 3D obtienes?", "Desplegado en cruz es uno de los más habituales para una forma muy conocida.", ["pirámide", "cuboide", "cubos", "prisma"], "Un entrecruzamiento de 6 cuadrados se pliega formando un cubo."],
    "TSR811_3_04": ["En un cubo de 3×3×3, ¿cuántos cubos pequeños tienen exactamente 3 caras visibles?", "Los cubos de las esquinas tienen 3 caras visibles. ¿Cuántas esquinas tiene un cubo?", ["4", "6", "8", "12"], "Un cubo tiene 8 esquinas. Cada cubo de esquina tiene exactamente 3 caras visibles."],
    "TSR811_3_05": ["Si pegas 2 cubos a una cara, ¿cuántas caras tiene la nueva forma en total?", "Cada cubo tiene 6 caras, pero 2 están ocultas donde están pegadas.", ["8", "10", "11", "12"], "6 + 6 = 12 caras en total. Resta 2 caras ocultas: 12 − 2 = 10."],
    "TSR811_3_06": ["En un cubo de 3×3×3, ¿cuántos cubos pequeños tienen exactamente 2 caras visibles?", "Los cubos en los bordes (no en las esquinas) tienen 2 caras visibles. ¿Cuántas aristas tiene un cubo?", ["6", "8", "12", "24"], "Un cubo tiene 12 aristas. En cada arista hay 1 cubo que no es una esquina. 12 × 1 = 12 cubos de 2 caras."],
    "TSR811_3_07": ["Si cortas un cubo con un solo corte recto, ¿cuántas piezas obtienes como máximo?", "Un solo corte se divide en como máximo 2 partes.", ["2", "3", "4", "6"], "Un corte recto a través de cualquier forma produce como máximo 2 piezas."],
    "TSR811_3_08": ["En un cubo de 3×3×3, ¿cuántos cubos pequeños tienen exactamente 1 cara visible?", "Los cubos en el centro de cada cara tienen 1 cara visible. Un cubo tiene 6 caras.", ["4", "6", "8", "12"], "En cada una de las 6 caras hay 1 cubo central. 6 × 1 = 6 cubos con exactamente 1 cara."],
    "TSR811_3_09": ["¿De cuántas formas consta el despliegue de una pirámide de base cuadrada?", "Cuenta la base triangular y las caras.", ["4", "5", "6", "8"], "Se despliega en 5 formas: 1 cuadrado (base) + 4 triángulos (lados)."],
    "TSR811_3_10": ["Si pegas 3 cubos seguidos (cara a cara), ¿cuántas caras tiene la nueva forma?", "3 cubos = 18 caras en total. Hay 2 uniones, cada una de las cuales esconde 2 caras.", ["12", "14", "16", "18"], "3 × 6 = 18 caras. 2 uniones × 2 caras ocultas = 4 ocultas. 18 - 4 = 14."],
    "TSR811_3_11": ["En un cubo de 4×4×4 (64 cubos pequeños), ¿cuántos cubos pequeños hay en la superficie?", "Total de cubos menos los que están dentro. El interior es de 2×2×2.", ["48", "52", "56", "60"], "Interior = 2×2×2 = 8 cubos. Afuera = 64 − 8 = 56."],
    "TSR811_3_12": ["Si pintas un cubo de 3×3×3 y lo rompes en cubos pequeños, ¿cuántos no tienen pintura?", "Sólo el cubo en el centro exacto no tiene la cara pintada.", ["0", "1", "4", "8"], "Sólo el cubo del centro no toca el exterior, por lo que no tiene pintura."],
    "TSR811_3_13": ["¿Cuántas formas tiene una red para un prisma triangular?", "2 extremos triangulares + lados rectangulares.", ["3", "4", "5", "6"], "La red tiene 5 formas: 2 triángulos + 3 rectángulos."],
    "TSR811_3_14": ["Si pintas un cubo de 2×2×2 y lo divides en 8 cubos pequeños, ¿cuántas 3 caras exactamente se pintan?", "En 2×2×2, cada cubo está en la esquina.", ["4", "6", "8", "2"], "Los 8 están en la esquina, por lo que todos tienen exactamente 3 caras pintadas."],
    "TSR811_3_15": ["Mirando un cubo desde una esquina, ¿cuántas caras puedes ver al mismo tiempo?", "Desde una esquina se ven las caras que se encuentran allí.", ["1", "2", "3", "4"], "Desde una esquina del cubo se ven como máximo 3 caras."],
    "TSR811_3_16": ["En un cubo de 3×3×3, ¿el número total de caras pequeñas visibles en el exterior es…?", "El cubo grande tiene 6 caras, cada una con 9 caras pequeñas.", ["36", "48", "54", "27"], "6 caras grandes × 9 caras pequeñas = 54 caras pequeñas visibles."],
    "TSR811_3_17": ["Si pegas 2 cubos uno al lado del otro y pones el tercero encima de uno (forma de L), ¿cuántas caras tiene la forma?", "2 cubos pegados = 10 caras. El tercero de arriba esconde 2 caras más.", ["12", "14", "16", "18"], "2 cubos pegados = 10 caras. Tercer cubo: 10 + 6 − 2 = 14 caras."],
    "TSR811_3_18": ["¿Cuántos cubos pequeños se necesitan para construir un cubo de 4×4×4?", "Multiplica 4 × 4 × 4.", ["16", "32", "48", "64"], "4 × 4 × 4 = 64 cubos pequeños."],
    "TSR811_3_19": ["En un cubo de 3×3×3, ¿cuántos cubos pequeños comparten una cara con el cubo central?", "El cubo central está tocado por los cubos superior, inferior, izquierdo, derecho, frontal y posterior.", ["4", "6", "8", "12"], "Se puede llegar al cubo central desde 6 direcciones: arriba, abajo, izquierda, derecha, adelante, atrás."],
    "TSR811_3_20": ["Si pegas 6 cubos en un rectángulo plano de 2×3×1, ¿cuántas caras tiene la forma?", "6 cubos = 36 caras. Cuenta las uniones internas que ocultan caras.", ["18", "20", "22", "24"], "6×6 = 36 caras. Hay 7 juntas internas (4 horizontales + 3 verticales), cada una de las cuales oculta 2 caras: 36 − 14 = 22."],
    "TMP811_1_01": ["Un granjero tiene 25 ovejas. Todos huyen excepto 9. ¿Cuántas ovejas quedan?", "\"Todos menos 9\" significa que 9 no se ejecutó.", ["16", "9", "25", "0"], "\"Todos menos 9 corren\" significa que 9 se quedan. La respuesta es 9."],
    "TMP811_1_02": ["3 amigos comparten 12 galletas en partes iguales. ¿Cuánto recibe cada uno?", "Divide 12 entre 3.", ["3", "4", "5", "6"], "12 ÷ 3 = 4 galletas cada una."],
    "TMP811_1_03": ["Una tienda vende manzanas a £2 cada una. ¿Cuánto cuestan 5 manzanas?", "Multiplica el precio unitario por la cantidad de manzanas.", ["£7", "£8", "£10", "£12"], "5 × 2 libras = 10 libras."],
    "TMP811_1_04": ["¿Cuántos meses del año tienen 28 días?", "Piénselo: ¿sólo algunos meses tienen 28 días?", ["1", "6", "12", "2"], "¡Los 12 meses tienen al menos 28 días!"],
    "TMP811_1_05": ["Un libro tiene 6 capítulos, cada uno con 10 páginas. ¿Cuántas páginas tiene en total?", "Multiplique el número de capítulos por las páginas por capítulo.", ["16", "50", "60", "66"], "6×10 = 60 páginas."],
    "TMP811_1_06": ["Tienes 3 cajas, cada una con 4 bolas. ¿Cuántas bolas tienes en total?", "Multiplica las cajas por las bolas de cada caja.", ["7", "9", "12", "15"], "3 × 4 = 12 bolas."],
    "TMP811_1_07": ["En una carrera, adelantas al segundo clasificado. ¿Dónde estás ahora?", "Si adelantas al que ocupa el segundo lugar, ocupas su lugar.", ["1er lugar", "2do lugar", "3er lugar", "4to lugar"], "Estás en 2do lugar. Pasaste el segundo, no el primero."],
    "TMP811_1_08": ["Un panadero hace 5 pasteles por hora. ¿Cuántas torturas hace en 4 horas?", "Multiplica las torturas por hora por el número de horas.", ["9", "15", "20", "25"], "5×4 = 20 tortas."],
    "TMP811_1_09": ["Tom tiene 8 juguetes. Recibe 3 más en su cumpleaños. ¿Cuánto tiene ahora?", "Añade juguetes nuevos a los que ya tenía.", ["5", "10", "11", "12"], "8 + 3 = 11 juguetes."],
    "TMP811_1_10": ["¿Qué pesa más: 1 kg de plumas o 1 kg de piedras?", "Mira el peso: ambos pesan 1 kg.", ["plumas", "las piedras", "igualmente", "depende"], "Ambos pesan 1 kg, ¡lo mismo!"],
    "TMP811_1_11": ["Una araña tiene 8 patas. ¿Cuántas patas tienen 3 arañas?", "Multiplica las patas de una araña por la cantidad de arañas.", ["16", "20", "24", "28"], "3 × 8 = 24 pies."],
    "TMP811_1_12": ["Tienes 20 caramelos y comes 3 al día. Después de 4 días ¿cuántos te quedan?", "Primero calcula cuánto comiste en total.", ["5", "8", "10", "12"], "4 × 3 = 12 comidos. 20 − 12 = quedan 8."],
    "TMP811_1_13": ["¿Cuántos lados tiene un círculo?", "Un lado es una regla. ¿El círculo tiene bordes rectos?", ["0", "1", "2", "4"], "Un círculo tiene 0 lados rectos."],
    "TMP811_1_14": ["Un auto tiene 4 ruedas. ¿Cuántas ruedas tienen 5 autos?", "Multiplica las ruedas de un auto por la cantidad de autos.", ["9", "15", "16", "20"], "5 × 4 = 20 ruedas."],
    "TMP811_1_15": ["Una docena de huevos equivale a 12. ¿Cuántos huevos hay media docena?", "La mitad de 12 es...", ["4", "5", "6", "8"], "Media docena = 12 ÷ 2 = 6."],
    "TMP811_1_16": ["Si hoy es tu noveno cumpleaños, ¿cuántos cumpleaños has cumplido hasta ahora?", "El primer cumpleaños fue cuando cumpliste 1 año; ahora es el 9.", ["8", "9", "10", "1"], "El noveno cumpleaños significa que lo has celebrado 9 veces."],
    "TMP811_1_17": ["Una semana tiene 7 días. ¿Cuántos días hay en 3 semanas?", "Multiplica los días de una semana por el número de semanas.", ["10", "14", "21", "28"], "3 × 7 = 21 días."],
    "TMP811_1_18": ["Tienes £5,00 y gastas £1,50. ¿Cuanto te queda?", "Resta lo que gastaste.", ["£2.50", "£3.00", "£3.50", "£4.00"], "5,00 £ - 1,50 £ = 3,50 £."],
    "TMP811_1_19": ["4 amigos tienen 6 pelotas cada uno. ¿Cuántas pelotas tienen juntas?", "Multiplica el número de amigos por las pelotas de cada persona.", ["10", "18", "20", "24"], "4×6 = 24 bolas."],
    "TMP811_1_20": ["¿Cuantos minutos hay en media hora?", "Una hora tiene 60 minutos.", ["20", "25", "30", "45"], "La mitad de 60 minutos = 30 minutos."],
    "TMP811_2_01": ["Un caracol camina 3 cm en un minuto. ¿Qué distancia recorre en 10 minutos?", "Multiplica la velocidad por el tiempo.", ["13cm", "30cm", "33cm", "300cm"], "3×10=30cm."],
    "TMP811_2_02": ["En un cuadrado mágico, cada fila suma 15. La primera fila es: 2, ?, 6. ¿Cuál es el número que falta?", "2+? + 6 = 15.", ["5", "6", "7", "8"], "2+? + 6 = 15, entonces? = 15 - 2 - 6 = 7."],
    "TMP811_2_03": ["Se dividen 24 dulces en partes iguales entre 6 niños. ¿Cuánto recibe cada uno?", "Divida los caramelos según el número de niños.", ["3", "4", "5", "6"], "24 ÷ 6 = 4 caramelos cada uno."],
    "TMP811_2_04": ["Un grifo llena un balde en 10 minutos. ¿Cuántos baldes puede llenar en una hora?", "1 hora = 60 minutos.", ["4", "5", "6", "10"], "60 ÷ 10 = 6 cubos."],
    "TMP811_2_05": ["En un cuadrado mágico (suma 15), una fila es: 6, 5, ?. ¿Cuál es el número que falta?", "6+5+? = 15.", ["3", "4", "5", "6"], "6+5+? = 15, entonces? = 15 - 6 - 5 = 4."],
    "TMP811_2_06": ["Una bicicleta recorre 12 km por hora. ¿Qué distancia recorre en 3 horas?", "Multiplica la velocidad por el tiempo.", ["15 kilometros", "24 kilometros", "36 kilometros", "48 kilometros"], "12 × 3 = 36 kilómetros."],
    "TMP811_2_07": ["3 amigos encuentran £30 y los dividen en partes iguales. ¿Cuánto recibe cada uno?", "Divide £30 entre 3.", ["£5", "£10", "£12", "£15"], "£30 ÷ 3 = £10 cada uno."],
    "TMP811_2_08": ["Una fábrica fabrica 50 juguetes al día. ¿Cuánto gana en 5 días?", "Multiplica los juguetes por día por la cantidad de días.", ["55", "100", "200", "250"], "50 × 5 = 250 juguetes."],
    "TMP811_2_09": ["En un cuadrado mágico (suma 15), una fila es: 8, 3, ?. ¿Cuál es el número que falta?", "8+3+? = 15.", ["3", "4", "5", "6"], "8+3+? = 15, entonces? = 15 - 8 - 3 = 4."],
    "TMP811_2_10": ["Compras 3 productos por 4,50€ cada uno. ¿Cuanto pagas en total?", "Multiplica el precio por la cantidad.", ["£12.00", "13,50€", "£14.50", "£15.00"], "3 × 4,50 £ = 13,50 £."],
    "TMP811_2_11": ["Un tren viaja a 60 km por hora. ¿Qué distancia recorre en 2 horas?", "Multiplica la velocidad por el tiempo.", ["62 kilometros", "90 kilometros", "100 kilometros", "120 kilometros"], "60 × 2 = 120 kilómetros."],
    "TMP811_2_12": ["Se colocan 36 manzanas en cajas de 9. ¿Cuántas cajas se necesitan?", "Divide 36 entre 9.", ["3", "4", "5", "6"], "36 ÷ 9 = 4 cajas."],
    "TMP811_2_13": ["En un cuadrado mágico (suma 15), una fila es: 8, 1, ?. ¿Cuál es el número que falta?", "8+1+? = 15.", ["4", "5", "6", "7"], "8+1+? = 15, entonces? = 15 - 8 - 1 = 6."],
    "TMP811_2_14": ["Tienes £20. Un libro cuesta £3,50. ¿Cuántos libros puedes permitirte comprar?", "Deja £3,50 repetidamente hasta que no puedas.", ["4", "5", "6", "7"], "5 × 3,50 £ = 17,50 £ (suficiente). 6 × £3,50 = £21,00 (demasiado). Puedes comprar 5."],
    "TMP811_2_15": ["Una manguera de jardín llena 2 litros por minuto. ¿Cuantos litros hay en 15 minutos?", "Multiplica el flujo por el tiempo.", ["17", "25", "30", "32"], "2×15 = 30 litros."],
    "TMP811_2_16": ["5 niños comparten a partes iguales 35 pegatinas. ¿Cuánto recibe cada uno?", "Divide 35 entre 5.", ["5", "6", "7", "8"], "35 ÷ 5 = 7 pegatinas cada una."],
    "TMP811_2_17": ["En un cuadrado mágico (suma 15), una fila es: 4, 9, ?. ¿Cuál es el número que falta?", "4+9+? = 15.", ["1", "2", "3", "4"], "4+9+? = 15, entonces? = 15 - 4 - 9 = 2."],
    "TMP811_2_18": ["Ahorra £5 a la semana. ¿En cuántas semanas recaudarás £40?", "Divida £40 por £5.", ["6", "7", "8", "9"], "£40 ÷ £5 = 8 semanas."],
    "TMP811_2_19": ["Una impresora imprime 10 páginas por minuto. ¿Cuánto tiempo se tarda en imprimir 80 páginas?", "Divide las páginas en páginas por minuto.", ["6 minutos", "7 minutos", "8 minutos", "10 minutos"], "80 ÷ 10 = 8 minutos."],
    "TMP811_2_20": ["48 estudiantes se dividen en equipos de 8. ¿Cuántos equipos se forman?", "Divide 48 entre 8.", ["4", "5", "6", "7"], "48 ÷ 8 = 6 equipos."],
    "TMP811_3_01": ["Una tienda vende lápices por 50 peniques y bolígrafos por £1,20. Compras 3 lápices y 2 bolígrafos. ¿Cuanto pagas?", "Calcula cada parte por separado y luego súmalas.", ["£3.50", "3,90€", "£4.10", "£4.50"], "3 × 50p = £1,50. 2 × 1,20 £ = 2,40 £. Total: 1,50 £ + 2,40 £ = 3,90 £."],
    "TMP811_3_02": ["Una araña tiene 8 patas, un perro tiene 4. Hay 3 arañas y 2 perros en una habitación. ¿Cuántos pies hay en total?", "Calcula primero las patas de las arañas y luego las de los perros.", ["28", "30", "32", "36"], "3 × 8 = 24 patas (arañas). 2 × 4 = 8 pies (perros). 24 + 8 = 32."],
    "TMP811_3_03": ["El reloj marca las 15:45. ¿Qué hora será en 2 horas y 30 minutos?", "Suma primero las horas y luego los minutos.", ["17:15", "17:45", "18:15", "18:45"], "15:45 + 2 horas = 17:45. 17:45 + 30 minutos = 18:15."],
    "TMP811_3_04": ["Tienes 3 monedas: 50p, 20p y 10p. ¿Cuántas cantidades diferentes puedes formar usando una o más monedas?", "Enumere todas las combinaciones: una, dos, las tres.", ["5", "6", "7", "8"], "Individuales: 50, 20, 10. Parejas: 70, 60, 30. Los tres: 80. Total 7 cantidades."],
    "TMP811_3_05": ["Una receta requiere 250 g de harina para 4 personas. ¿Cuánta harina necesitas para 12 personas?", "12 es 3 veces más que 4.", ["500 gramos", "625 gramos", "750 gramos", "1000g"], "12 ÷ 4 = 3 veces más. 250 × 3 = 750 gramos."],
    "TMP811_3_06": ["Un tren sale a las 9:15 y llega a las 11:45. ¿Cuánto dura el viaje?", "Cuente las horas y los minutos.", ["2 horas", "2 horas y 15 minutos", "2 horas y 30 minutos", "3 horas"], "De 9:15 a 11:15 = 2 horas. De 11:15 a 11:45 = 30 minutos. Total: 2 horas y 30 minutos."],
    "TMP811_3_07": ["Compras productos que cuestan £2,50, £3,75, £1,25 y £4,50. ¿Cuánto dinero obtienes con 20 libras?", "Sume todos los precios y luego reste £20.", ["£6.00", "£7.00", "£8.00", "£9.00"], "2,50 £ + 3,75 £ + 1,25 £ + 4,50 £ = 12,00 £. Resto: £20 − £12 = £8,00."],
    "TMP811_3_08": ["En una habitación hay sillas (de 4 pies cada una) y taburetes (de 3 pies cada una). Hay 5 sillas y algunos taburetes. En total son 29 pies. ¿Cuantos taburetes hay?", "Primero calcula las patas de la silla y luego encuentra los taburetes.", ["2", "3", "4", "5"], "5 sillas × 4 = 20 pies. 29 − 20 = quedan 9 pies. 9 ÷ 3 = 3 deposiciones."],
    "TMP811_3_09": ["Se necesitan 5 minutos para cortar un tronco en 2 pedazos. ¿Cuánto tiempo se tarda en cortarlo en 4 pedazos?", "Para 4 piezas necesitas 3 cortes, no 4.", ["10 minutos", "15 minutos", "20 minutos", "25 minutos"], "4 piezas = 3 cortes. 3×5 = 15 minutos."],
    "TMP811_3_10": ["Un autobús transporta 45 pasajeros. Se necesitan 3 autobuses para un viaje escolar. ¿Cuál es el número máximo de estudiantes que pueden ir?", "Multiplica los asientos del autobús por el número de autobuses.", ["90", "120", "135", "150"], "3 × 45 = 135 alumnos como máximo."],
    "TMP811_3_11": ["Empiezas con £100. Gastas una cuarta parte y luego un tercio de lo que queda. ¿Cuanto te queda?", "Un cuarto de 100 = 25. Luego un tercio de 75.", ["£40", "£45", "£50", "£55"], "Un cuarto de £100 = £25 gastados, quedan £75. Un tercio de £75 = £25 gastados. £75 − £25 = £50."],
    "TMP811_3_12": ["Una sesión comienza a las 14:50 y dura 1 hora y 25 minutos. ¿A qué hora termina?", "Agregue 1 hora, luego 25 minutos.", ["15:55", "4:05 p.m.", "16:15", "4:25 p.m."], "14:50 + 1 hora = 15:50. 15:50 + 25 minutos = 16:15."],
    "TMP811_3_13": ["En una clase hay el doble de niñas que de niños. Hay 12 chicos. ¿Cuántos niños hay en total?", "Niñas = 2 × niños.", ["24", "30", "36", "48"], "Niñas = 2 × 12 = 24. Total = 12 + 24 = 36 niños."],
    "TMP811_3_14": ["Quieres vallar un jardín cuadrado con un lado de 8m. La valla cuesta 5 libras por metro. ¿Cuál es el costo total?", "Primero encuentra el perímetro y luego multiplícalo por el precio del metro.", ["£120", "£140", "£160", "£ 200"], "Perímetro = 4 × 8 = 32 m. Costo = 32 × £5 = £160."],
    "TMP811_3_15": ["Una película empieza a las 19:40 y dura 1 hora y 50 minutos. ¿A qué hora termina?", "Agregue 1 hora (obtendrá 20:40), luego 50 minutos.", ["21:10", "21:20", "21:30", "21:40"], "19:40 + 1 hora = 20:40. 20:40 + 50 min = 21:30."],
    "TMP811_3_16": ["Hay vacas y gallinas en un patio. Números 8 cabezas y 26 pies. cuantas vacas hay", "La vaca tiene 4 patas, la gallina 2. Puedes comprobarlo intentándolo.", ["3", "4", "5", "6"], "8 cabezas. Si fueran todas gallinas: 8 × 2 = 16 pies. Además: 26 − 16 = 10. Cada vaca añade 2 patas extra: 10 ÷ 2 = 5 vacas."],
    "TMP811_3_17": ["Usando monedas de 5p, 10p y 20p, ¿de cuántas maneras diferentes puedes ganar exactamente 25p?", "Enumera todas las combinaciones que suman 25p.", ["2", "3", "4", "5"], "Cuatro modos: (1) 20+5, (2) 10+10+5, (3) 10+5+5+5, (4) 5+5+5+5+5."],
    "TMP811_3_18": ["Una pista para correr tiene 400 m de largo. Un atleta corre 3 vueltas. ¿Cuántos kilómetros recorre?", "1 kilómetro = 1000 metros.", ["0,8 kilometros", "1,0 kilometros", "1,2 kilómetros", "1,5 kilómetros"], "3 × 400 = 1200 m = 1,2 km."],
    "TMP811_3_19": ["Una caja contiene 24 dulces. Lo necesitas para 100 personas (una para cada una). ¿Cuántas cajas necesitas comprar?", "4 cajas = 96 (no es suficiente). Pruebe con 5 cajas.", ["4", "5", "6", "10"], "4 cajas = 96 (no es suficiente). 5 cajas = 120 (suficiente). Debes comprar 5."],
    "TMP811_3_20": ["Dos números suman 50. Uno es 14 mayor que el otro. ¿Cuál es el número mayor?", "Marca el número más pequeño con una x. Entonces x + (x + 14) = 50.", ["28", "30", "32", "36"], "x + (x + 14) = 50. 2x = 36. x = 18. Mayor = 18 + 14 = 32."],
  }
});
